window.calcVDrop=()=>{const I=v('vd-i'),L=v('vd-l'),V=v('vd-v'),a=sv('vd-a'),R=RCU[a]||0.1;const Vd=2*I*L*R/1000,pct=Vd/V*100;setRes('nec','VOLTAGE DROP',grid([['V_drop',F(Vd,3)+' V'],['%',F(pct,2)+' %'],['Status',pct<=3?fos(3):pct<=5?fos(1):fos(0.5)]]),note('NEC informational: ≤3% branch, ≤5% combined. Larger AWG or shorter run if exceeded.'));};
window.calcFatigue=()=>{const sm=v('fg-sm'),sa=v('fg-sa'),Sut=v('fg-sut'),Sy=v('fg-sy'),Se=v('fg-se'),Kf=v('fg-kf')||1;const sae=Kf*sa,nG=1/(sae/Se+sm/Sut),nS=1/(sae/Se+sm/Sy),nE=1/Math.sqrt(Math.pow(sae/Se,2)+Math.pow(sm/Sy,2)),disc=Math.max(0,1-Math.pow((nG*sm)/Sut,2));const nGer=disc>0?(Sut*Sut)/(2*sm*Se)*(-1+Math.sqrt(1+Math.pow(2*sae*Sut/(Se*Sut),2))):nG;setRes('fatigue','FATIGUE FoS',grid([['σ_a (Kf·σ_a)',F(sae,2)+' MPa'],['Goodman n',F(nG,2)],['Soderberg n',F(nS,2)],['ASME-Elliptic n',F(nE,2)]]),note('Goodman = standard mean-stress. Soderberg conservative (uses Sy). ASME-Elliptic for ductile. n ≥ 1.5 typical.'));const xs=[],g=[],s=[];for(let m=0;m<=Sut;m+=Sut/50){xs.push(m);g.push(Math.max(0,Se*(1-m/Sut)));s.push(m<=Sy?Math.max(0,Se*(1-m/Sy)):null);}plot('p-fatigue',[{x:xs,y:g,name:'Goodman',line:{color:acc}},{x:xs,y:s,name:'Soderberg',line:{color:warn}},{x:[sm],y:[sae],mode:'markers',name:'op',marker:{color:err,size:10}}],{xaxis:{title:'σ_mean (MPa)',range:[0,Sut]},yaxis:{title:'σ_alt (MPa)'},showlegend:true,legend:{font:{size:9}}});};
window.calcThermalCond=()=>{const k=v('tc-k'),A=v('tc-a'),L=v('tc-l'),Th=v('tc-th'),Tc=v('tc-tc');const q=k*A*(Th-Tc)/L,R=L/(k*A);setRes('thermal','CONDUCTION',grid([['q',F(q,1)+' W'],['R_th',F(R,4)+' K/W'],['ΔT',F(Th-Tc,1)+' K'],['q/A',F(q/A,1)+' W/m²']]),note('Fourier 1-D plane wall. Add convective resistances in series for full UA. R = L/(kA).'));const xs=[0,L*1000],ys=[Th,Tc];plot('p-thermal',[{x:xs,y:ys,line:{color:acc}}],{xaxis:{title:'x (mm)'},yaxis:{title:'T (°C)'}});};
window.calcThermalConv=()=>{const h=v('tv-h'),A=v('tv-a'),Ts=v('tv-ts'),Ti=v('tv-ti');const q=h*A*(Ts-Ti);setRes('thermal','CONVECTION',grid([['q',F(q,1)+' W'],['R_conv',F(1/(h*A),4)+' K/W'],['ΔT',F(Ts-Ti,1)+' K']]),note('Newton cooling. Natural h: 5-25; forced air 25-250; water 100-15000; boiling 2500-100000 W/m²K.'));const dTs=[],qs=[];for(let dT=0;dT<=Math.max(1,Ts-Ti)*2;dT+=(Ts-Ti||1)*2/40){dTs.push(Ti+dT);qs.push(h*A*dT);}plot('p-thermal',[{x:dTs,y:qs,line:{color:acc}},{x:[Ts],y:[q],mode:'markers',marker:{color:err,size:10}}],{xaxis:{title:'T_s (°C)'},yaxis:{title:'q (W)'}});};
window.calcThermalRad=()=>{const e=v('tr-e'),A=v('tr-a'),Ts=v('tr-ts')+273.15,Ta=v('tr-ta')+273.15;const q=e*5.67e-8*A*(Math.pow(Ts,4)-Math.pow(Ta,4));setRes('thermal','RADIATION',grid([['q',F(q,1)+' W'],['σ·T_s⁴',F(5.67e-8*Math.pow(Ts,4),1)+' W/m²'],['ε·σ·A',F(e*5.67e-8*A,4)]]),note('Stefan-Boltzmann to large surroundings. Dominant for >300°C. Polished metal ε≈0.05; oxidized ≈0.7; matte black ≈0.95.'));const Tmax=Math.max(Ts,Ta)+100,xs=[],ys=[];for(let T=Math.max(200,Ta);T<=Tmax;T+=(Tmax-Math.max(200,Ta))/40){xs.push(T-273.15);ys.push(e*5.67e-8*A*(Math.pow(T,4)-Math.pow(Ta,4)));}plot('p-thermal',[{x:xs,y:ys,line:{color:acc}},{x:[Ts-273.15],y:[q],mode:'markers',marker:{color:err,size:10}}],{xaxis:{title:'T_s (°C)'},yaxis:{title:'q_rad (W)'}});};
window.calcThermalFin=()=>{const k=v('tf-k'),h=v('tf-h'),P=v('tf-p'),Ac=v('tf-ac'),L=v('tf-l'),Tb=v('tf-tb'),Ti=v('tf-ti');const m=Math.sqrt(h*P/(k*Ac)),mL=m*L,th=Tb-Ti,q=Math.sqrt(h*P*k*Ac)*th*Math.tanh(mL),eff=Math.tanh(mL)/mL;setRes('thermal','FIN',grid([['m',F(m,3)+' 1/m'],['mL',F(mL,3)],['q_fin',F(q,2)+' W'],['η_fin',F(eff*100,1)+' %']]),note('Adiabatic tip approx. mL > 2.5 → diminishing returns. Optimal mL ≈ 1-1.5 for cost/perf.'));const xs=[],ys=[];for(let x=0;x<=L;x+=L/40){xs.push(x*1000);ys.push(Ti+th*Math.cosh(m*(L-x))/Math.cosh(m*L));}plot('p-thermal',[{x:xs,y:ys,line:{color:acc}},{x:[0],y:[Tb],mode:'markers',marker:{color:err,size:10,symbol:'circle'}},{x:[L*1000],y:[Ti+th/Math.cosh(mL)],mode:'markers',marker:{color:warn,size:8}}],{xaxis:{title:'x (mm)'},yaxis:{title:'T (°C)'}});};
window.calcNernst=()=>{const E0=v('nr-e0'),T=v('nr-t'),n=v('nr-n')||1,Q=v('nr-q')||1;const E=E0-8.314*T/(n*96485)*Math.log(Q);setRes('echem','NERNST',grid([['E°',F(E0,4)+' V'],['T',F(T,2)+' K'],['Q',F(Q,4)],['E',F(E,4)+' V']]),note('E = E° − (RT/nF)·ln(Q). Standard 25°C → 0.0592/n·log10(Q).'));const lqs=[],es=[];for(let lq=-6;lq<=6;lq+=0.2){const q=Math.pow(10,lq);lqs.push(lq);es.push(E0-8.314*T/(n*96485)*Math.log(q));}plot('p-echem',[{x:lqs,y:es,name:'E(Q)',line:{color:acc}},{x:[Math.log10(Q||1e-9)],y:[E],mode:'markers',name:'op',marker:{color:err,size:10}}],{xaxis:{title:'log₁₀(Q)'},yaxis:{title:'E (V)'},showlegend:false});};
window.calcTafel=()=>{const eta=v('tf2-eta'),i0=v('tf2-i0'),b=v('tf2-b');const i=i0*Math.pow(10,eta/b);setRes('echem','TAFEL',grid([['η',F(eta,3)+' V'],['i₀',F(i0,4)+' A/m²'],['β',F(b,3)+' V/dec'],['i',F(i,4)+' A/m²']]),note('High-overpotential approx. β typical 0.06-0.12 V/dec.'));const xs=[],ys=[];for(let e=0;e<=eta*2+0.05;e+=0.005){xs.push(e);ys.push(i0*Math.pow(10,e/b));}plot('p-echem',[{x:xs,y:ys,line:{color:acc}},{x:[eta],y:[i],mode:'markers',marker:{color:err,size:10}}],{xaxis:{title:'η (V)'},yaxis:{title:'i (A/m²)',type:'log'}});};
window.calcButlerVolmer=()=>{const eta=v('bv-eta'),i0=v('bv-i0'),a=v('bv-a'),n=v('bv-n')||1,T=v('bv-t');const RT=8.314*T,F0=96485,i=i0*(Math.exp(a*n*F0*eta/RT)-Math.exp(-(1-a)*n*F0*eta/RT));setRes('echem','BUTLER-VOLMER',grid([['i',F(i,4)+' A/m²'],['α',F(a,2)],['Anodic dom.',a>0.5?'Yes':'No']]),note('Symmetric (α=0.5) typical. Reduces to Tafel for |η|·nF/RT > 2.'));const etas=[],is=[];for(let e=-0.3;e<=0.3;e+=0.005){etas.push(e);is.push(i0*(Math.exp(a*n*F0*e/RT)-Math.exp(-(1-a)*n*F0*e/RT)));}plot('p-echem',[{x:etas,y:is,name:'i(η)',line:{color:acc}},{x:[eta],y:[i],mode:'markers',name:'op',marker:{color:err,size:10}}],{xaxis:{title:'η (V)',zeroline:true},yaxis:{title:'i (A/m²)',zeroline:true},showlegend:false});};
window.calcCorrosionRate=()=>{const i=v('cr-i'),EW=v('cr-ew'),r=v('cr-rho');const cr=3.27e-3*i*EW/r;setRes('echem','CORROSION RATE',grid([['CR',F(cr,4)+' mm/yr'],['CR',F(cr*39.37,2)+' mpy'],['Class',cr<0.025?'Outstanding':cr<0.1?'Excellent':cr<0.5?'Good':cr<1?'Fair':'Poor']]),note('NACE: <0.1 mm/yr good for most service. ASTM G102 conversion 3.27e-3·i·EW/ρ.'));};
window.calcFaraday=()=>{const I=v('fd-i'),t=v('fd-t'),M=v('fd-m'),n=v('fd-n')||1,e=v('fd-eff')||1;const m=I*t*M/(n*96485)*e;setRes('echem','FARADAY',grid([['m',F(m,3)+' g'],['Charge',F(I*t,1)+' C'],['Moles',F(I*t*e/(n*96485),5)]]),note('m = (I·t·M·η)/(n·F). Plating thickness: t_plt = m/(ρ·A).'));};
window.calcPack=()=>{const Vc=v('bp-vc'),Qc=v('bp-qc'),S=v('bp-s'),P=v('bp-p');const Vp=Vc*S,Qp=Qc*P,Wh=Vp*Qp;setRes('battery','PACK',grid([['V_pack',F(Vp,2)+' V'],['Q_pack',F(Qp,2)+' Ah'],['Energy',F(Wh,1)+' Wh'],['Cells',F(S*P,0)]]),note('Series ↑V, parallel ↑Q. Add 10-15% derate for BMS/temperature/EOL.'));};
window.calcRuntime=()=>{const Q=v('rt-q'),I=v('rt-i'),d=v('rt-dod')||1;const t=Q*d/I;setRes('battery','RUNTIME',grid([['Run time',F(t,2)+' h'],['Run time',F(t*60,1)+' min'],['DoD',F(d*100,0)+'%']]),note('Linear approx; Peukert correction needed for high C-rates.'));const xs=[],ys=[];for(let cur=I*0.2;cur<=I*5;cur+=I*0.1){xs.push(cur);ys.push(Q*d/cur);}plot('p-battery',[{x:xs,y:ys,line:{color:acc}},{x:[I],y:[t],mode:'markers',marker:{color:err,size:10}}],{xaxis:{title:'I (A)'},yaxis:{title:'t (hr)'}});};
window.calcPeukert=()=>{const C=v('pk-c'),H=v('pk-h'),I=v('pk-i'),k=v('pk-k')||1.1;const t=H*Math.pow(C/(I*H),k);setRes('battery','PEUKERT',grid([['Run time',F(t,3)+' h'],['k',F(k,3)],['Eff. Q',F(I*t,2)+' Ah']]),note('Higher k (1.1-1.4 lead-acid) penalises high I. Li-ion k≈1.05.'));};
