if(res.error){document.getElementById('seal-results').innerHTML=`<h3>SEAL RESULTS</h3><p style="color:var(--err)">${res.error}</p>`;return;}
const gland=(String(res.gland_type||inp.gland_type||'face')).toLowerCase();
